<?php declare(strict_types=1); $title='Árkalkuláció előnézet – A Bata'; require __DIR__.'/_layout_start.php'; $e=static fn(mixed $v):string=>htmlspecialchars((string)$v,ENT_QUOTES|ENT_SUBSTITUTE,'UTF-8'); ?>
<section class="admin-page" aria-labelledby="preview-title"><p class="eyebrow">Árkezelés</p><h1 id="preview-title">Árkalkuláció előnézet</h1><?php if($error!==null): ?><div class="alert" role="alert"><?= $e($error) ?></div><?php else: ?><dl class="facts"><div><dt>Végösszeg</dt><dd class="total"><?= $e($result->totalAmount) ?> <?= $e($result->currency) ?></dd></div><div><dt>Szállásdíj</dt><dd><?= $e($result->accommodationFee) ?> <?= $e($result->currency) ?></dd></div><div><dt>IFA</dt><dd><?= $e($result->tourismTax) ?> <?= $e($result->currency) ?></dd></div><div><dt>Alkalmazott szabályok</dt><dd><?= $e(implode(', ', $result->appliedRuleIds)) ?></dd></div></dl><h2>Tételek</h2><div class="table-scroll" tabindex="0" role="region" aria-label="Árkalkuláció tételei"><table><thead><tr><th>Megnevezés</th><th>Mennyiség</th><th>Összeg</th></tr></thead><tbody><?php foreach($result->lineItems as $item): ?><tr><td><?= $e($item['description']??$item['type']??'') ?></td><td><?= $e($item['quantity']??'') ?></td><td><?= $e($item['total']??'') ?> <?= $e($result->currency) ?></td></tr><?php endforeach ?></tbody></table></div><?php endif ?><p><a class="button-link" href="/admin/pricing">Vissza az árképzéshez</a></p></section><?php require __DIR__.'/_layout_end.php'; ?>
